export enum Category {
  ALL = 'Tất cả',
  ELECTRONICS = 'Điện tử',
  FASHION = 'Thời trang',
  HOME = 'Nhà cửa',
  BEAUTY = 'Làm đẹp'
}

export type BadgeType = 'Deal hot' | 'Bán chạy' | 'Giảm sâu';

export interface Product {
  id: string;
  name: string;
  category: Category;
  originalPrice: number;
  discountedPrice: number;
  imageUrl: string;
  affiliateUrl: string;
  badges: BadgeType[];
}

export interface WhyUsPoint {
  title: string;
  description: string;
  icon: React.ReactNode;
}

import React from 'react';
import { Product } from '../types';
import { ShoppingCart, ExternalLink } from 'lucide-react';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(price);
  };

  const getBadgeClass = (badge: string) => {
    switch (badge) {
      case 'Deal hot': return 'bg-red-500 text-white';
      case 'Bán chạy': return 'bg-orange-500 text-white';
      case 'Giảm sâu': return 'bg-purple-600 text-white';
      default: return 'bg-gray-500 text-white';
    }
  };

  return (
    <div className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 border border-gray-100 flex flex-col h-full">
      <div className="relative aspect-square overflow-hidden bg-gray-100">
        <img 
          src={product.imageUrl} 
          alt={product.name} 
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
        />
        <div className="absolute top-2 left-2 flex flex-col gap-1">
          {product.badges.map((badge) => (
            <span 
              key={badge} 
              className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${getBadgeClass(badge)}`}
            >
              {badge}
            </span>
          ))}
        </div>
      </div>

      <div className="p-4 flex flex-col flex-grow">
        <h3 className="text-sm font-semibold text-gray-800 line-clamp-2 mb-2 group-hover:text-[#EE4D2D] transition-colors">
          {product.name}
        </h3>

        <div className="mt-auto">
          <div className="flex items-center gap-2 mb-1">
            <span className="text-xs text-gray-400 line-through font-medium">
              {formatPrice(product.originalPrice)}
            </span>
            <span className="text-[10px] bg-red-100 text-red-600 px-1 font-bold rounded">
              -{Math.round((1 - product.discountedPrice / product.originalPrice) * 100)}%
            </span>
          </div>
          <div className="text-lg font-bold text-[#EE4D2D] mb-4">
            {formatPrice(product.discountedPrice)}
          </div>

          <a 
            href={product.affiliateUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            className="w-full flex items-center justify-center gap-2 bg-[#EE4D2D] text-white py-2.5 rounded-xl font-bold text-sm hover:bg-[#d73a1a] transition-colors shadow-lg shadow-orange-200 active:scale-95 transform"
          >
            Mua Ngay <ExternalLink size={16} />
          </a>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

