import React, { useState, useMemo, useEffect } from 'react';
import { 
  ShoppingBag, 
  ChevronRight, 
  Share2, 
  Facebook, 
  MessageCircle, 
  Star, 
  ShieldCheck, 
  LayoutGrid, 
  Clock, 
  Phone, 
  ExternalLink,
  Loader2
} from 'lucide-react';
import { WHY_US, PRODUCTS as FALLBACK_PRODUCTS } from './constants';
import { Category, Product, BadgeType } from './types';
import ProductCard from './components/ProductCard';

// URL Google Sheet xuất dưới dạng CSV
const SHEET_CSV_URL = "https://docs.google.com/spreadsheets/d/e/2PACX-1vRbNK9b5-GWuRl4yLJBBgXoEht-fZGugORleRU9_0zB5UOV7w9rcJ3OHWmTu_yqJJ5fKBvIcPtmADor/pub?gid=0&single=true&output=csv";

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);

    // Fetch dữ liệu từ Google Sheet
    fetchSheetData();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchSheetData = async () => {
    try {
      setLoading(true);
      const response = await fetch(SHEET_CSV_URL);
      const csvText = await response.text();

      // Parse CSV đơn giản (bỏ qua dòng đầu tiên là tiêu đề)
      const lines = csvText.split('\n').slice(1);
      const parsedProducts: Product[] = lines
        .map((line, index) => {
          // Xử lý split CSV có tính đến dấu ngoặc kép (nếu có)
          const columns = line.match(/(".*?"|[^",\r\n]+)(?=\s*,|\s*$)/g);

          if (!columns || columns.length < 7) return null;

          const clean = (str: string) => str.replace(/^"|"$/g, '').trim();

          return {
            id: clean(columns[0]) || `p-${index}`,
            name: clean(columns[1]),
            category: (clean(columns[2]) as Category) || Category.ALL,
            originalPrice: parseInt(clean(columns[3]).replace(/\D/g, '')) || 0,
            discountedPrice: parseInt(clean(columns[4]).replace(/\D/g, '')) || 0,
            imageUrl: clean(columns[5]),
            affiliateUrl: clean(columns[6]),
            badges: clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(b => b)
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts.length > 0 ? parsedProducts : FALLBACK_PRODUCTS);
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu từ Google Sheet:", error);
      setProducts(FALLBACK_PRODUCTS); // Fallback nếu lỗi
    } finally {
      setLoading(false);
    }
  };

  const filteredProducts = useMemo(() => {
    if (activeCategory === Category.ALL) return products;
    return products.filter(p => p.category === activeCategory);
  }, [activeCategory, products]);

