    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung"
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Top Contact Bar */}
      <div className="bg-gray-900 text-white py-2 text-xs font-medium z-[60] relative">
        <div className="container mx-auto px-4 flex flex-col sm:flex-row justify-between items-center gap-2">
          <div className="flex items-center gap-4">
            <a href={`tel:${CONTACT.phone}`} className="flex items-center gap-1.5 hover:text-[#EE4D2D] transition-colors">
              <Phone size={14} /> Hotline: {CONTACT.phone}
            </a>
            <span className="hidden sm:inline text-gray-700">|</span>
            <span className="hidden sm:inline">Giao hàng toàn quốc</span>
          </div>
          <div className="flex items-center gap-4">
            <a href={CONTACT.facebook} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 hover:text-[#EE4D2D] transition-colors">
              <Facebook size={14} /> Facebook
            </a>
            <a href={CONTACT.zalo} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 hover:text-[#EE4D2D] transition-colors">
              <MessageCircle size={14} /> Zalo: {CONTACT.phone}
            </a>
          </div>
        </div>
      </div>

      {/* Header */}
      <header className={`fixed top-8 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white shadow-md py-3 top-0' : 'bg-white/80 backdrop-blur-md py-5'}`}>
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-2 group cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
            <div className="bg-[#EE4D2D] p-1.5 rounded-lg group-hover:rotate-12 transition-transform shadow-lg shadow-orange-200">
              <ShieldCheck className="text-white w-6 h-6" />
            </div>
            <div className="flex flex-col leading-none">
              <span className="text-xl font-black tracking-tighter text-gray-900">
                TỔNG KHO <span className="text-[#EE4D2D]">TỦ SẤY UV</span>
              </span>
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">Uy tín - Chất lượng - Tận tâm</span>
            </div>
          </div>
          <div className="flex gap-3">
            <a 
              href={CONTACT.zalo}
              target="_blank"
              rel="noopener noreferrer"
              className="hidden md:flex items-center gap-2 bg-blue-50 text-blue-600 px-4 py-2 rounded-xl text-sm font-bold hover:bg-blue-100 transition-all"
            >
              Chat Zalo
            </a>
            <a 
              href="https://shopee.vn" 
              target="_blank" 
              rel="noopener noreferrer"
              className="bg-[#EE4D2D] text-white px-5 py-2 rounded-xl text-sm font-bold shadow-lg shadow-orange-200 hover:scale-105 active:scale-95 transition-all flex items-center gap-2"
            >
              Mua tại Shopee <ExternalLink size={14} />
            </a>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <section className="relative pt-40 pb-20 md:pt-56 md:pb-32 overflow-hidden bg-white">
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
           <div className="absolute -top-24 -left-24 w-96 h-96 bg-[#EE4D2D] rounded-full blur-3xl"></div>
           <div className="absolute -bottom-24 -right-24 w-96 h-96 bg-[#EE4D2D] rounded-full blur-3xl"></div>
        </div>

        <div className="container mx-auto px-4 text-center relative z-10">
          <div className="inline-flex items-center gap-2 bg-orange-50 border border-orange-100 px-4 py-1.5 rounded-full mb-6 animate-pulse">
            <ShieldCheck size={16} className="text-[#EE4D2D]" />
            <span className="text-[#EE4D2D] text-xs font-bold uppercase tracking-wider">Phân Phối Sỉ & Lẻ Toàn Quốc</span>
          </div>

          <h1 className="text-4xl md:text-7xl font-black text-gray-900 mb-6 leading-tight">
            Giải pháp tiệt trùng <br/>
            <span className="text-[#EE4D2D]">Đúng chuẩn - Giá tận kho</span>
          </h1>

          <p className="text-gray-500 text-lg md:text-xl max-w-2xl mx-auto mb-10 leading-relaxed">
            Chuyên cung cấp các dòng tủ sấy UV tiệt trùng cho gia đình, spa và y tế. Cam kết hàng chính hãng, bảo hành dài hạn, giá tốt nhất thị trường.
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button 
              onClick={scrollToDeals}
              className="w-full sm:w-auto bg-[#EE4D2D] text-white px-10 py-4 rounded-2xl font-bold text-lg shadow-2xl shadow-orange-300 hover:bg-[#d73a1a] transition-all transform hover:-translate-y-1 flex items-center justify-center gap-2"
            >
              Xem danh mục sản phẩm <ChevronRight />
            </button>
            <a 
              href={`tel:${CONTACT.phone}`}
              className="w-full sm:w-auto bg-gray-900 text-white px-10 py-4 rounded-2xl font-bold text-lg shadow-xl shadow-gray-200 hover:bg-black transition-all transform hover:-translate-y-1 flex items-center justify-center gap-2"
            >
              Gọi ngay: {CONTACT.phone}
            </a>
          </div>
        </div>
      </section>

      {/* Catalog Section */}
      <section id="catalog" className="py-16 bg-gray-50 min-h-[600px]">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row md:items-end justify-between mb-10 gap-6">
            <div>
              <h2 className="text-2xl md:text-3xl font-black text-gray-900 mb-2">Sản Phẩm Nổi Bật</h2>
              <p className="text-gray-500">Các dòng tủ sấy & thiết bị tiệt trùng mới nhất từ kho</p>
            </div>

            {/* Category Scrollable Filter */}
            <div className="flex overflow-x-auto gap-3 pb-2 no-scrollbar -mx-4 px-4 md:mx-0 md:px-0">
              {Object.values(Category).map((cat) => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`whitespace-nowrap px-6 py-2.5 rounded-xl font-bold text-sm transition-all border-2 ${
                    activeCategory === cat 
                      ? 'bg-[#EE4D2D] border-[#EE4D2D] text-white shadow-lg shadow-orange-100' 
                      : 'bg-white border-gray-100 text-gray-500 hover:border-gray-200'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          {loading ? (
            <div className="flex flex-col items-center justify-center py-32 bg-white rounded-3xl border border-gray-100 shadow-sm">
              <Loader2 className="w-12 h-12 text-[#EE4D2D] animate-spin mb-4" />
