  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [scrolled, setScrolled] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const CONTACT = {
    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung"
  };

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);

    fetchData();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      // Thêm cache-buster để tránh trình duyệt lấy dữ liệu cũ
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      const csvText = await response.text();

      // Parse CSV logic
      const lines = csvText.split(/\r?\n/);
      // Lọc các dòng trống
      const dataRows = lines.slice(1).filter(line => line.trim() !== ''); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          // Xử lý split CSV thông minh để tránh lỗi khi dữ liệu chứa dấu phẩy bên trong ngoặc kép
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

          if (columns.length < 7) return null;

          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';

          return {
            id: clean(columns[0]) || `id-${index}`,
            name: clean(columns[1]),
            category: (clean(columns[2]) as Category) || Category.ALL,
            originalPrice: parseInt(clean(columns[3]).replace(/\D/g, '')) || 0,
            discountedPrice: parseInt(clean(columns[4]).replace(/\D/g, '')) || 0,
            imageUrl: clean(columns[5]),
            affiliateUrl: clean(columns[6]),
            badges: clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(Boolean)
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' }));
    } catch (err) {
      console.error("Lỗi tải dữ liệu từ Google Sheet:", err);
    } finally {
      setLoading(false);
    }
  };

  const filteredProducts = useMemo(() => {
    if (activeCategory === Category.ALL) return products;
    return products.filter(p => p.category === activeCategory);
  }, [activeCategory, products]);

  const scrollToDeals = () => {
    const el = document.getElementById('catalog');
    el?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Top Contact Bar */}
      <div className="bg-gray-900 text-white py-2.5 text-xs font-semibold z-[60] relative">
