import React from 'react';

export type Category = string;

export type BadgeType = 'Deal hot' | 'Bán chạy' | 'Giảm sâu';

export interface Product {
  id: string;
  name: string;
  category: Category;
  originalPrice: number;
  discountedPrice: number;
  imageUrl: string;
  affiliateUrl: string;
  badges: BadgeType[];
}

export interface WhyUsPoint {
  title: string;
  description: string;
  icon: React.ReactNode;
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  ShoppingBag, 
  ChevronRight, 
  Share2, 
  Facebook, 
  MessageCircle, 
  ShieldCheck, 
  LayoutGrid, 
  Clock, 
  Phone, 
  ExternalLink,
  Loader2,
  RefreshCw,
  Zap
} from 'lucide-react';
import { WHY_US, SHEET_CSV_URL } from './constants';
import { Category, Product, BadgeType } from './types';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('Tất cả');
  const [scrolled, setScrolled] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const CONTACT = {
    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung"
  };

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);

    fetchData();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      // Sử dụng cache-buster để đảm bảo lấy dữ liệu mới nhất từ Google Sheet
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      const csvText = await response.text();

      const lines = csvText.split(/\r?\n/);
      const dataRows = lines.slice(1).filter(line => line.trim() !== ''); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          // Xử lý split CSV nâng cao (giữ dấu phẩy bên trong ngoặc kép)
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

          if (columns.length < 7) return null;

          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';

          return {
            id: clean(columns[0]) || `id-${index}`,
            name: clean(columns[1]),
            category: clean(columns[2]) || 'Khác',
            originalPrice: parseInt(clean(columns[3]).replace(/\D/g, '')) || 0,
            discountedPrice: parseInt(clean(columns[4]).replace(/\D/g, '')) || 0,
            imageUrl: clean(columns[5]),
            affiliateUrl: clean(columns[6]),
            badges: clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(Boolean)
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' }));
    } catch (err) {
      console.error("Lỗi đồng bộ dữ liệu:", err);
    } finally {
      setLoading(false);
    }
  };

  // Tự động lấy danh sách Category từ dữ liệu sản phẩm
  const categories = useMemo(() => {
    const uniqueCategories = Array.from(new Set(products.map(p => p.category)));
    return ['Tất cả', ...uniqueCategories];
  }, [products]);

  const filteredProducts = useMemo(() => {
    if (activeCategory === 'Tất cả') return products;
    return products.filter(p => p.category === activeCategory);
  }, [activeCategory, products]);

  const scrollToCatalog = () => {
    const el = document.getElementById('catalog');
    el?.scrollIntoView({ behavior: 'smooth' });
