    address: "Tổng Kho Tủ Sấy UV, TP. Hồ Chí Minh & Hà Nội"
  };

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);
    fetchData();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      // Sử dụng cache-buster timestamp để đảm bảo Google Sheets trả về bản mới nhất
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      if (!response.ok) throw new Error('Network response was not ok');
      const csvText = await response.text();

      const lines = csvText.split(/\r?\n/);
      // Bỏ qua dòng tiêu đề và các dòng trống
      const dataRows = lines.slice(1).filter(line => line.trim() !== ''); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          // Xử lý split CSV thông minh: split theo dấu phẩy nhưng bỏ qua phẩy nằm trong ngoặc kép
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

          if (columns.length < 7) return null;

          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';

          return {
            id: clean(columns[0]) || `id-${index}`,
            name: clean(columns[1]),
            category: clean(columns[2]) || 'Khác',
            originalPrice: parseInt(clean(columns[3]).replace(/\D/g, '')) || 0,
            discountedPrice: parseInt(clean(columns[4]).replace(/\D/g, '')) || 0,
            imageUrl: clean(columns[5]),
            affiliateUrl: clean(columns[6]),
            badges: clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(Boolean)
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
    } catch (err) {
      console.error("Lỗi đồng bộ dữ liệu Google Sheet:", err);
    } finally {
      setLoading(false);
    }
  };

