            <div className={`p-2.5 rounded-2xl transition-all duration-500 shadow-xl ${scrolled ? 'bg-[#EE4D2D] rotate-0' : 'bg-white rotate-6'}`}>
              <ShieldCheck className={scrolled ? 'text-white w-7 h-7' : 'text-[#EE4D2D] w-7 h-7'} />
