import React, { useState, useMemo, useEffect } from 'react';
import { 
  ChevronRight, 
  Facebook, 
  MessageCircle, 
  ShieldCheck, 
  LayoutGrid, 
  Clock, 
  Phone, 
  ExternalLink,
  RefreshCw,
  Zap,
  ArrowUp,
  Mail,
  MapPin
} from 'lucide-react';
import { WHY_US, SHEET_CSV_URL } from './constants';
import { Category, Product, BadgeType } from './types';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('Tất cả');
  const [scrolled, setScrolled] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const CONTACT = {
    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung",
    address: "Tổng Kho Tủ Sấy UV, TP. Hồ Chí Minh & Hà Nội"
  };

  /**
   * Hàm fixImageUrl: Chuyển đổi mọi định dạng link Google Drive sang link ảnh trực tiếp.
   * Lưu ý quan trọng: File trên Google Drive phải được đặt ở chế độ "Bất kỳ ai có đường liên kết đều xem được".
   */
  const fixImageUrl = (url: string) => {
    if (!url || url.trim() === '') return 'https://via.placeholder.com/600x600?text=Chưa+có+ảnh';

    let driveId = '';

    if (url.includes('drive.google.com')) {
      // Trường hợp 1: Link dạng https://drive.google.com/file/d/ID_FILE/view
      const dMatch = url.match(/\/d\/([^/?#]+)/);
      if (dMatch && dMatch[1]) {
        driveId = dMatch[1];
      } 
      // Trường hợp 2: Link dạng https://drive.google.com/open?id=ID_FILE
      else {
        const idMatch = url.match(/[?&]id=([^&?#]+)/);
        if (idMatch && idMatch[1]) {
          driveId = idMatch[1];
        }
      }
    }

    if (driveId) {
      // Sử dụng format uc?export=view để nhúng trực tiếp ổn định hơn
      return `https://drive.google.com/uc?export=view&id=${driveId}`;
    }

    // Nếu không phải link Drive, giữ nguyên (link trực tiếp từ Shopee hoặc host khác)
    return url.trim();
  };

  const parsePrice = (val: string): number => {
    if (!val) return 0;
    const cleanValue = val.toString().replace(/\D/g, '');
    return parseInt(cleanValue) || 0;
  };

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);
    fetchData();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      if (!response.ok) throw new Error('Network response was not ok');
      const csvText = await response.text();

      const lines = csvText.split(/\r?\n/);
      const dataRows = lines.slice(1).filter(line => line.trim() !== ''); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

          if (columns.length < 7) return null;

          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';

          let original = parsePrice(clean(columns[3]));
          let discounted = parsePrice(clean(columns[4]));

          if (discounted > original && original !== 0) {
            [original, discounted] = [discounted, original];
          }
          if (original === 0) original = discounted;

          return {
            id: clean(columns[0]) || `id-${index}`,
            name: clean(columns[1]),
            category: clean(columns[2]) || 'Khác',
            originalPrice: original,
            discountedPrice: discounted,
            imageUrl: fixImageUrl(clean(columns[5])), // Áp dụng hàm sửa link ảnh
            affiliateUrl: clean(columns[6]),
            badges: clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(Boolean)
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
    } catch (err) {
      console.error("Lỗi đồng bộ dữ liệu Google Sheet:", err);
    } finally {
      setLoading(false);
    }
  };

