import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('Tất cả');
  const [scrolled, setScrolled] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const CONTACT = {
    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung",
    address: "Tổng Kho Tủ Sấy UV, TP. Hồ Chí Minh & Hà Nội"
  };

  /**
   * Hàm fixImageUrl: Chuyển đổi link Google Drive sang link trực tiếp (Direct Link)
   * Sử dụng domain lh3.googleusercontent.com - đây là cách hiển thị ảnh Drive ổn định nhất.
   */
  const fixImageUrl = (url: string) => {
    if (!url || typeof url !== 'string' || url.trim() === '') {
      return 'https://via.placeholder.com/600x600?text=S%E1%BA%A3n+Ph%E1%BA%A9m';
    }

    const trimmedUrl = url.trim();
    let driveId = '';

    // Kiểm tra nếu là link Google Drive
    if (trimmedUrl.includes('drive.google.com')) {
      // Tìm ID trong link /file/d/[ID]/view
      const dMatch = trimmedUrl.match(/\/d\/([^/?#\s]+)/);
      if (dMatch && dMatch[1]) {
        driveId = dMatch[1];
      } 
      // Tìm ID trong link ?id=[ID]
      else {
        const idMatch = trimmedUrl.match(/[?&]id=([^&?#\s]+)/);
        if (idMatch && idMatch[1]) {
          driveId = idMatch[1];
        }
      }
    }

    if (driveId) {
      // Định dạng lh3 là định dạng hiển thị ảnh trực tiếp mượt nhất của Google
      return `https://lh3.googleusercontent.com/d/${driveId}`;
    }

    // Nếu là link ảnh trực tiếp từ nơi khác thì giữ nguyên
    return trimmedUrl;
  };

  /**
   * Hàm parsePrice: Chuyển đổi văn bản giá tiền thành số
   */
  const parsePrice = (val: any): number => {
    if (!val) return 0;
    // Xóa tất cả các ký tự không phải là số (xóa dấu chấm, dấu phẩy, chữ đ...)
    const cleanValue = val.toString().replace(/\D/g, '');
    return parseInt(cleanValue, 10) || 0;
  };

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);
    fetchData();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      if (!response.ok) throw new Error('Không thể kết nối với dữ liệu Google Sheet');
      const csvText = await response.text();

      const lines = csvText.split(/\r?\n/);
      // Bỏ qua dòng tiêu đề, lọc các dòng trống
      const dataRows = lines.slice(1).filter(line => line.trim().length > 10); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          // Phân tách CSV xử lý được cả dấu phẩy nằm trong ngoặc kép
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

          if (columns.length < 7) return null;

          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';

          const name = clean(columns[1]);
          const category = clean(columns[2]) || 'Khác';
          let original = parsePrice(clean(columns[3]));
          let discounted = parsePrice(clean(columns[4]));
          const imageUrl = fixImageUrl(clean(columns[5]));
          const affiliateUrl = clean(columns[6]);
          const badges = clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(Boolean);

          // TỰ ĐỘNG SỬA LỖI GIÁ:
          // Nếu giá ưu đãi lớn hơn giá gốc, hoặc giá gốc bằng 0, chúng ta sẽ hoán đổi/điều chỉnh
          if (original === 0) original = discounted;
          if (discounted > original && original > 0) {
            const temp = original;
            original = discounted;
            discounted = temp;
          }
          // Nếu giá ưu đãi bằng 0, coi như không giảm giá
          if (discounted === 0) discounted = original;

          return {
            id: clean(columns[0]) || `prod-${index}`,
            name,
            category,
            originalPrice: original,
            discountedPrice: discounted,
            imageUrl,
            affiliateUrl,
            badges
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN'));
    } catch (err) {
      console.error("Lỗi đồng bộ dữ liệu:", err);
    } finally {
      setLoading(false);
    }
  };

  const categories = useMemo(() => {
    const uniqueCategories = Array.from(new Set(products.map(p => p.category))).filter(Boolean);
    return ['Tất cả', ...uniqueCategories];
  }, [products]);

  const filteredProducts = useMemo(() => {
    if (activeCategory === 'Tất cả') return products;
    return products.filter(p => p.category === activeCategory);
  }, [activeCategory, products]);

  const scrollToCatalog = () => {
    const el = document.getElementById('catalog');
    el?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-orange-100 selection:text-orange-600 bg-white">
      {/* Top bar thông báo trạng thái kết nối */}
      <div className="bg-gray-900 text-white py-2 text-[10px] md:text-xs font-bold uppercase tracking-widest z-[60] relative border-b border-gray-800">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </span>
              <span>Dữ liệu Live từ Google Sheet</span>
            </div>
          </div>
          <div className="flex items-center gap-6">
            <span className="text-gray-500 hidden md:inline">Cập nhật: {lastUpdated || '--:--'}</span>
            <a href={`tel:${CONTACT.phone}`} className="text-[#EE4D2D] hover:text-white transition-colors flex items-center gap-1">
              <Phone size={12} /> {CONTACT.phone}
            </a>
          </div>
        </div>
      </div>

      <header className={`fixed top-8 left-0 right-0 z-50 transition-all duration-500 ${scrolled ? 'bg-white/95 shadow-2xl py-3 top-0 backdrop-blur-lg border-b border-gray-100' : 'bg-transparent py-8'}`}>
