interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const [imgError, setImgError] = useState(false);

  const formatPrice = (price: number) => {
    if (!price || price === 0) return "Liên hệ";
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(price);
  };

  const getBadgeClass = (badge: string) => {
    switch (badge) {
      case 'Deal hot': return 'bg-red-500 text-white';
      case 'Bán chạy': return 'bg-orange-500 text-white';
      case 'Giảm sâu': return 'bg-purple-600 text-white';
      default: return 'bg-gray-500 text-white';
    }
  };

  const handleImageError = () => {
    setImgError(true);
  };

  // Tính phần trăm giảm giá an toàn
  const discountPercent = product.originalPrice > product.discountedPrice 
    ? Math.round((1 - product.discountedPrice / product.originalPrice) * 100)
    : 0;

  return (
    <div className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-2xl transition-all duration-500 border border-gray-100 flex flex-col h-full relative">
      {/* Container Ảnh */}
      <div className="relative aspect-square overflow-hidden bg-gray-50">
        {!imgError ? (
          <img 
            src={product.imageUrl} 
            alt={product.name} 
            onError={handleImageError}
            loading="lazy"
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-gray-300 gap-2">
            <ImageOff size={40} />
            <span className="text-[10px] font-bold uppercase">Ảnh không tồn tại</span>
          </div>
        )}

        {/* Badges nhãn dán */}
        <div className="absolute top-2 left-2 flex flex-col gap-1 z-10">
          {product.badges.map((badge) => (
            <span 
              key={badge} 
              className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-wider shadow-sm ${getBadgeClass(badge)}`}
            >
              {badge}
            </span>
          ))}
        </div>

        {/* Overlay khi hover */}
        <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
      </div>

      {/* Nội dung sản phẩm */}
      <div className="p-3 md:p-5 flex flex-col flex-grow bg-white">
        <h3 className="text-xs md:text-sm font-bold text-gray-800 line-clamp-2 mb-3 h-10 group-hover:text-[#EE4D2D] transition-colors leading-snug">
          {product.name}
        </h3>

        <div className="mt-auto">
          {/* Hiển thị giá gốc nếu có giảm giá */}
          {discountPercent > 0 && (
            <div className="flex items-center gap-2 mb-1">
              <span className="text-[10px] md:text-xs text-gray-400 line-through font-medium">
                {formatPrice(product.originalPrice)}
              </span>
              <span className="text-[9px] md:text-[10px] bg-red-100 text-red-600 px-1.5 py-0.5 font-black rounded-md">
                -{discountPercent}%
              </span>
            </div>
          )}

          <div className="text-base md:text-xl font-black text-[#EE4D2D] mb-4 tracking-tighter">
            {formatPrice(product.discountedPrice)}
          </div>

          <a 
            href={product.affiliateUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            className="w-full flex items-center justify-center gap-2 bg-[#EE4D2D] text-white py-3 rounded-xl font-black text-xs md:text-sm hover:bg-gray-900 transition-all shadow-xl shadow-orange-100 active:scale-95 transform uppercase italic"
          >
            Mua Ngay <ExternalLink size={14} />
          </a>
        </div>
      </div>
    </div>
  );
};

