  };

  /**
   * Hàm fixImageUrl: Chuyển đổi link Google Drive sang link trực tiếp ổn định nhất (lh3)
   */
  const fixImageUrl = (url: string) => {
    if (!url || typeof url !== 'string' || url.trim() === '') {
      return 'https://via.placeholder.com/600x600?text=S%E1%BA%A3n+Ph%E1%BA%A9m';
    }

    const trimmedUrl = url.trim();
    let driveId = '';

    if (trimmedUrl.includes('drive.google.com')) {
      const dMatch = trimmedUrl.match(/\/d\/([^/?#\s]+)/);
      if (dMatch && dMatch[1]) {
        driveId = dMatch[1];
      } else {
        const idMatch = trimmedUrl.match(/[?&]id=([^&?#\s]+)/);
        if (idMatch && idMatch[1]) {
          driveId = idMatch[1];
        }
      }
    }

    if (driveId) {
      return `https://lh3.googleusercontent.com/d/${driveId}`;
    }
    return trimmedUrl;
  };

  /**
   * Hàm parsePrice: Chuyển đổi văn bản giá tiền thành số nguyên
   */
  const parsePrice = (val: any): number => {
    if (!val) return 0;
    const cleanValue = val.toString().replace(/\D/g, '');
    return parseInt(cleanValue, 10) || 0;
  };

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener('scroll', handleScroll);
    fetchData();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      if (!response.ok) throw new Error('Không thể kết nối với dữ liệu Google Sheet');
      const csvText = await response.text();

      const lines = csvText.split(/\r?\n/);
      const dataRows = lines.slice(1).filter(line => line.trim().length > 10); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);
          if (columns.length < 7) return null;

