  };

  /**
   * Hàm fixImageUrl: Chuyển đổi link Google Drive sang link Thumbnail trực tiếp.
   * Phương pháp Thumbnail API (sz=w1000) là cách ổn định nhất để hiển thị ảnh từ Drive.
   */
  const fixImageUrl = (url: string) => {
    if (!url || typeof url !== 'string' || url.trim() === '') {
      return 'https://via.placeholder.com/600x600?text=S%E1%BA%A3n+Ph%E1%BA%A9m';
    }

    const trimmedUrl = url.trim();
    let driveId = '';

    // Xử lý các định dạng link Google Drive phổ biến
    if (trimmedUrl.includes('drive.google.com')) {
      // 1. Link dạng /file/d/ID/view
      const dMatch = trimmedUrl.match(/\/d\/([a-zA-Z0-9_-]{25,})/);
      if (dMatch && dMatch[1]) {
        driveId = dMatch[1];
      } 
      // 2. Link dạng ?id=ID
      else {
        const idMatch = trimmedUrl.match(/[?&]id=([a-zA-Z0-9_-]{25,})/);
        if (idMatch && idMatch[1]) {
          driveId = idMatch[1];
        }
      }
    }

    if (driveId) {
      // Sử dụng Thumbnail API: Ổn định, tải nhanh và tự động nén ảnh tối ưu
      return `https://drive.google.com/thumbnail?id=${driveId}&sz=w1000`;
    }

    // Nếu là link ảnh trực tiếp từ nguồn khác (Shopee, Imgur...)
    return trimmedUrl;
  };

  const parsePrice = (val: any): number => {
    if (!val) return 0;
    const cleanValue = val.toString().replace(/\D/g, '');
    return parseInt(cleanValue, 10) || 0;
  };

