import React, { useState } from 'react';
import { Product } from '../types';
import { ShoppingCart, ExternalLink, ImageOff } from 'lucide-react';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const [imgError, setImgError] = useState(false);

  const formatPrice = (price: number) => {
    if (!price || price === 0) return "Liên hệ giá";
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(price);
  };

  const getBadgeClass = (badge: string) => {
    switch (badge) {
      case 'Deal hot': return 'bg-red-500 text-white';
      case 'Bán chạy': return 'bg-orange-500 text-white';
      case 'Giảm sâu': return 'bg-purple-600 text-white';
      default: return 'bg-gray-600 text-white';
    }
  };

  const handleImageError = () => {
    setImgError(true);
  };

  // Tính phần trăm giảm giá (chỉ hiển thị nếu giá giảm thấp hơn giá gốc)
  const discountPercent = product.originalPrice > product.discountedPrice 
    ? Math.round((1 - product.discountedPrice / product.originalPrice) * 100)
    : 0;

  return (
    <div className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-2xl transition-all duration-500 border border-gray-100 flex flex-col h-full relative">
      {/* Product Image */}
      <div className="relative aspect-square overflow-hidden bg-gray-50 flex items-center justify-center">
        {!imgError ? (
          <img 
            src={product.imageUrl} 
            alt={product.name} 
            onError={handleImageError}
            loading="lazy"
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-gray-300 gap-3 bg-gray-50 border-b border-gray-100">
            <ImageOff size={48} strokeWidth={1.5} />
            <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Ảnh đang cập nhật</span>
          </div>
        )}

        {/* Floating Badges */}
        <div className="absolute top-2 left-2 flex flex-col gap-1.5 z-10">
          {product.badges.map((badge) => (
            <span 
              key={badge} 
              className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-wider shadow-md ${getBadgeClass(badge)}`}
            >
              {badge}
            </span>
          ))}
          {discountPercent > 0 && (
            <span className="bg-yellow-400 text-gray-900 px-2 py-1 rounded-lg text-[10px] font-black uppercase shadow-md animate-pulse">
              -{discountPercent}%
            </span>
          )}
        </div>

        {/* Hover Overlay */}
        <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
      </div>

      {/* Product Info */}
      <div className="p-3 md:p-5 flex flex-col flex-grow bg-white">
        <h3 className="text-xs md:text-sm font-bold text-gray-800 line-clamp-2 mb-3 h-10 group-hover:text-[#EE4D2D] transition-colors leading-snug tracking-tight">
          {product.name}
        </h3>

        <div className="mt-auto">
          {/* Prices Section */}
          <div className="flex flex-col mb-4">
            {discountPercent > 0 ? (
              <>
                <span className="text-[10px] md:text-xs text-gray-400 line-through font-medium mb-0.5 opacity-60">
                  {formatPrice(product.originalPrice)}
                </span>
                <div className="text-base md:text-xl font-black text-[#EE4D2D] tracking-tighter italic">
                  {formatPrice(product.discountedPrice)}
                </div>
              </>
            ) : (
              <div className="text-base md:text-xl font-black text-gray-900 tracking-tighter italic">
                {formatPrice(product.originalPrice)}
              </div>
            )}
          </div>

          <a 
            href={product.affiliateUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            className="w-full flex items-center justify-center gap-2 bg-[#EE4D2D] text-white py-3.5 rounded-xl font-black text-xs md:text-sm hover:bg-gray-900 transition-all shadow-xl shadow-orange-100 active:scale-95 transform uppercase italic tracking-tighter"
          >
            Mua Ngay <ExternalLink size={14} className="group-hover:translate-x-0.5 transition-transform" />
          </a>
        </div>
      </div>
    </div>
  );
};

