import React, { useState, useMemo, useEffect } from 'react';
import { 
  ChevronRight, 
  Facebook, 
  MessageCircle, 
  ShieldCheck, 
  Phone, 
  RefreshCw,
  Zap,
  ArrowUp
} from 'lucide-react';
import { WHY_US, SHEET_CSV_URL } from './constants';
import { Category, Product, BadgeType } from './types';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('Tất cả');
  const [scrolled, setScrolled] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const CONTACT = {
    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung",
    address: "Tổng Kho Tủ Sấy UV, TP. Hồ Chí Minh & Hà Nội"
  };

  const fixImageUrl = (url: string) => {
    if (!url || typeof url !== 'string' || url.trim() === '') {
      return 'https://via.placeholder.com/600x600?text=H%C3%ACnh+%E1%BA%A3nh+đang+cập+nhật';
    }
    const trimmedUrl = url.trim();
    let driveId = '';
    if (trimmedUrl.includes('drive.google.com')) {
      const dMatch = trimmedUrl.match(/\/d\/([a-zA-Z0-9_-]{25,})/);
      if (dMatch && dMatch[1]) driveId = dMatch[1];
      else {
        const idMatch = trimmedUrl.match(/[?&]id=([a-zA-Z0-9_-]{25,})/);
        if (idMatch && idMatch[1]) driveId = idMatch[1];
      }
    }
    return driveId ? `https://drive.google.com/thumbnail?id=${driveId}&sz=w1000` : trimmedUrl;
  };

  /**
   * Hàm parsePrice: Xử lý thông minh các định dạng giá từ Google Sheet
   */
  const parsePrice = (val: any): number => {
    if (!val) return 0;
    // Loại bỏ dấu chấm, phẩy, khoảng trắng và ký hiệu tiền tệ
    const cleanValue = val.toString()
      .replace(/[.\s,đĐvVnNlL-]/g, '')
      .trim();
    return parseInt(cleanValue, 10) || 0;
  };

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', handleScroll);
    fetchData();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      if (!response.ok) throw new Error('Không thể tải dữ liệu');
      const csvText = await response.text();
      const lines = csvText.split(/\r?\n/);
      const dataRows = lines.slice(1).filter(line => line.trim().length > 10); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);
          if (columns.length < 6) return null;

          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';

          // Mapping theo thứ tự cột trong Sheet của bạn
          let original = parsePrice(clean(columns[3])); // Cột D: Giá gốc
          let discounted = parsePrice(clean(columns[4])); // Cột E: Giá ưu đãi

          // Xử lý logic hiển thị nếu dữ liệu nhập thiếu
          if (discounted === 0 && original > 0) discounted = original;
          if (original === 0 && discounted > 0) original = discounted;

          // Đảm bảo giá gốc luôn >= giá ưu đãi để tránh lỗi hiển thị gạch ngang
          if (original > 0 && discounted > original) {
            [original, discounted] = [discounted, original];
          }

          return {
            id: clean(columns[0]) || `p-${index}`,
            name: clean(columns[1]),
            category: clean(columns[2]) || 'Khác',
            originalPrice: original,
            discountedPrice: discounted,
            imageUrl: fixImageUrl(clean(columns[5])),
            affiliateUrl: clean(columns[6] || '#'),
            badges: clean(columns[7] || '').split(',').map(b => b.trim() as BadgeType).filter(b => b)
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN'));
    } catch (err) {
      console.error("Lỗi đồng bộ:", err);
    } finally {
      setLoading(false);
    }
  };

  const categories = useMemo(() => {
    const unique = Array.from(new Set(products.map(p => p.category))).filter(Boolean);
    return ['Tất cả', ...unique];
  }, [products]);

  const filteredProducts = useMemo(() => {
    if (activeCategory === 'Tất cả') return products;
    return products.filter(p => p.category === activeCategory);
  }, [activeCategory, products]);

  return (
    <div className="min-h-screen flex flex-col selection:bg-orange-100 selection:text-orange-600 bg-white">
      {/* Top Bar */}
      <div className="bg-gray-950 text-white py-2 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] z-[60] relative border-b border-gray-800">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
            </span>
            <span className="hidden sm:inline">Dữ liệu Live từ Google Sheet</span>
            <span className="sm:hidden">Live Data</span>
          </div>
          <div className="flex items-center gap-6">
            <span className="text-gray-500 hidden md:inline italic">Cập nhật lúc: {lastUpdated}</span>
            <a href={`tel:${CONTACT.phone}`} className="text-[#EE4D2D] hover:text-white transition-colors flex items-center gap-1 font-black">
              <Phone size={12} className="fill-[#EE4D2D]" /> {CONTACT.phone}
            </a>
          </div>
        </div>
      </div>

      <header className={`fixed top-8 left-0 right-0 z-50 transition-all duration-500 ${scrolled ? 'bg-white/95 shadow-2xl py-3 top-0 backdrop-blur-lg border-b border-gray-100' : 'bg-transparent py-8'}`}>
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-4 group cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
            <div className={`p-2.5 rounded-2xl transition-all duration-500 shadow-xl ${scrolled ? 'bg-[#EE4D2D]' : 'bg-white'}`}>
              <ShieldCheck className={scrolled ? 'text-white w-7 h-7' : 'text-[#EE4D2D] w-7 h-7'} />
            </div>
            <div className="flex flex-col leading-none">
              <span className="text-xl md:text-3xl font-black tracking-tighter uppercase text-gray-900">
                TỔNG KHO <span className="text-[#EE4D2D]">UV</span>
              </span>
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.4em] mt-1">Catalog Hệ Thống</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={fetchData} className="p-3 rounded-2xl border bg-white hover:bg-gray-50 transition-all border-gray-100 hidden sm:flex">
              <RefreshCw size={20} className={`${loading ? 'animate-spin text-[#EE4D2D]' : 'text-gray-400'}`} />
            </button>
            <a href={CONTACT.zalo} target="_blank" rel="noopener noreferrer" className="bg-[#EE4D2D] text-white px-6 md:px-10 py-3.5 rounded-2xl font-black text-sm md:text-base shadow-2xl shadow-orange-200 hover:scale-105 active:scale-95 transition-all uppercase italic">
              Liên Hệ Zalo
            </a>
          </div>
        </div>
      </header>

      <section className="relative pt-48 pb-20 md:pt-72 md:pb-48 overflow-hidden bg-white">
        <div className="container mx-auto px-4 text-center relative z-10">
          <div className="inline-flex items-center gap-3 bg-white border border-gray-100 px-6 py-3 rounded-full mb-12 shadow-2xl shadow-gray-100/80">
            <Zap size={20} className="text-orange-500 fill-orange-500 animate-pulse" />
            <span className="text-gray-900 text-[10px] md:text-sm font-black uppercase tracking-[0.2em]">Cập nhật giá sỉ mới nhất</span>
          </div>
          <h1 className="text-5xl md:text-[86px] font-black text-gray-900 mb-10 leading-[0.95] tracking-tighter italic uppercase">
            Deal <span className="text-[#EE4D2D]">Tủ Sấy UV</span> <br className="hidden md:block"/>
            <span className="relative">Giá Ưu Đãi Mỗi Ngày</span>
          </h1>
          <p className="text-gray-500 text-lg md:text-2xl max-w-4xl mx-auto mb-16 leading-relaxed font-medium italic">
            Hệ thống phân phối thiết bị tiệt trùng tia cực tím chuyên dụng - Cam kết giá rẻ nhất thị trường.
          </p>
          <button onClick={() => document.getElementById('catalog')?.scrollIntoView({ behavior: 'smooth' })} className="group bg-[#EE4D2D] text-white px-16 py-6 rounded-[2rem] font-black text-xl shadow-2xl shadow-orange-300 hover:bg-gray-900 transition-all transform hover:-translate-y-1 flex items-center justify-center gap-3 uppercase italic mx-auto">
            Xem Catalog Ngay <ChevronRight size={28} />
          </button>
        </div>
      </section>

      <section id="catalog" className="py-32 bg-gray-50 min-h-[800px] border-t border-gray-100">
