              <p className="text-gray-500 text-lg md:text-xl font-medium">Giá gốc và giá khuyến mãi được cập nhật liên tục từ hệ thống.</p>
            </div>
            <div className="flex overflow-x-auto gap-3 pb-4 no-scrollbar">
              {categories.map((cat) => (
                <button
                  key={cat}
