import React, { useState } from 'react';
import { Product } from '../types';
import { ExternalLink, ImageOff } from 'lucide-react';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const [imgError, setImgError] = useState(false);

  const formatPrice = (price: number) => {
    if (!price || price === 0) return "Liên hệ giá";
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(price);
  };

  const getBadgeClass = (badge: string) => {
    switch (badge) {
      case 'Deal hot': return 'bg-red-500 text-white';
      case 'Bán chạy': return 'bg-orange-500 text-white';
      case 'Giảm sâu': return 'bg-purple-600 text-white';
      default: return 'bg-gray-600 text-white';
    }
  };

  // Chỉ coi là có khuyến mãi nếu giá ưu đãi thực sự nhỏ hơn giá gốc
  const isSale = product.originalPrice > product.discountedPrice && product.discountedPrice > 0;

  const discountPercent = isSale 
    ? Math.round((1 - product.discountedPrice / product.originalPrice) * 100)
    : 0;

  return (
    <div className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-2xl transition-all duration-500 border border-gray-100 flex flex-col h-full relative">
      <div className="relative aspect-square overflow-hidden bg-gray-50 flex items-center justify-center">
        {!imgError ? (
          <img 
            src={product.imageUrl} 
            alt={product.name} 
            onError={() => setImgError(true)}
            loading="lazy"
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-gray-300 gap-3 bg-gray-50">
            <ImageOff size={40} strokeWidth={1.5} />
            <span className="text-[10px] font-black uppercase tracking-widest text-gray-400 text-center px-2">Hình ảnh đang cập nhật</span>
          </div>
        )}

        <div className="absolute top-2 left-2 flex flex-col gap-1.5 z-10">
          {product.badges.map((badge) => (
            <span key={badge} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-wider shadow-md ${getBadgeClass(badge)}`}>
              {badge}
            </span>
          ))}
          {isSale && (
            <span className="bg-yellow-400 text-gray-900 px-2 py-1 rounded-lg text-[10px] font-black uppercase shadow-md animate-pulse">
              -{discountPercent}%
            </span>
          )}
        </div>
      </div>

      <div className="p-3 md:p-5 flex flex-col flex-grow bg-white">
        <h3 className="text-xs md:text-sm font-bold text-gray-800 line-clamp-2 mb-3 h-10 group-hover:text-[#EE4D2D] transition-colors leading-snug">
          {product.name}
        </h3>

        <div className="mt-auto">
          <div className="flex flex-col mb-4 min-h-[48px] justify-end">
            {isSale ? (
              <>
                <span className="text-[10px] md:text-xs text-gray-400 line-through font-medium opacity-70">
                  {formatPrice(product.originalPrice)}
                </span>
                <div className="text-base md:text-xl font-black text-[#EE4D2D] tracking-tighter italic leading-none mt-1">
                  {formatPrice(product.discountedPrice)}
                </div>
              </>
            ) : (
              <div className="text-base md:text-xl font-black text-gray-900 tracking-tighter italic leading-none">
                {formatPrice(product.discountedPrice || product.originalPrice)}
              </div>
            )}
          </div>

          <a 
            href={product.affiliateUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            className="w-full flex items-center justify-center gap-2 bg-[#EE4D2D] text-white py-3.5 rounded-xl font-black text-xs md:text-sm hover:bg-gray-900 transition-all shadow-xl shadow-orange-100 active:scale-95 transform uppercase italic"
          >
            Mua Ngay <ExternalLink size={14} className="group-hover:translate-x-0.5 transition-transform" />
          </a>
        </div>
      </div>
    </div>
  );
};

