import React, { useState } from 'react';
import { Product } from '../types';
import { ExternalLink, ImageOff } from 'lucide-react';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const [imgError, setImgError] = useState(false);

  const formatPrice = (price: number) => {
    if (!price || price === 0) return "Liên hệ giá";
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(price);
  };

  const getBadgeClass = (badge: string) => {
    switch (badge) {
      case 'Deal hot': return 'bg-red-500 text-white';
      case 'Bán chạy': return 'bg-orange-500 text-white';
      case 'Giảm sâu': return 'bg-purple-600 text-white';
      default: return 'bg-gray-600 text-white';
    }
  };

  const isSale = product.originalPrice > product.discountedPrice && product.discountedPrice > 0;
  const discountPercent = isSale 
    ? Math.round((1 - product.discountedPrice / product.originalPrice) * 100)
    : 0;

  return (
    <div className="group bg-white rounded-3xl overflow-hidden shadow-sm hover:shadow-2xl transition-all duration-500 border border-gray-100 flex flex-col h-full relative">
      <div className="relative aspect-square overflow-hidden bg-gray-50 flex items-center justify-center">
        {!imgError ? (
          <img 
            src={product.imageUrl} 
            alt={product.name} 
            onError={() => setImgError(true)}
            loading="lazy"
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-gray-300 gap-4 bg-gray-50">
            <ImageOff size={44} strokeWidth={1} />
            <span className="text-[10px] font-black uppercase tracking-widest text-gray-400 text-center px-4 leading-relaxed">Hình ảnh đang cập nhật</span>
          </div>
        )}

        <div className="absolute top-3 left-3 flex flex-col gap-2 z-10">
          {product.badges.map((badge) => (
            <span key={badge} className={`px-2.5 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-wider shadow-lg ${getBadgeClass(badge)}`}>
              {badge}
            </span>
          ))}
          {isSale && (
            <span className="bg-yellow-400 text-gray-950 px-2.5 py-1.5 rounded-xl text-[10px] font-black uppercase shadow-lg animate-pulse">
              -{discountPercent}%
            </span>
          )}
        </div>
      </div>

      <div className="p-4 md:p-6 flex flex-col flex-grow bg-white">
        <h3 className="text-sm md:text-base font-bold text-gray-800 line-clamp-2 mb-4 h-[3rem] group-hover:text-[#EE4D2D] transition-colors leading-[1.45] tracking-tight">
          {product.name}
        </h3>

        <div className="mt-auto">
          <div className="flex flex-col mb-5 min-h-[56px] justify-end">
            {isSale ? (
              <>
                <span className="text-[11px] md:text-xs text-gray-400 line-through font-semibold opacity-60 tracking-tighter">
                  {formatPrice(product.originalPrice)}
                </span>
                <div className="text-lg md:text-2xl font-black text-[#EE4D2D] tracking-tighter italic leading-none mt-2">
                  {formatPrice(product.discountedPrice)}
                </div>
              </>
            ) : (
              <div className="text-lg md:text-2xl font-black text-gray-900 tracking-tighter italic leading-none">
                {formatPrice(product.discountedPrice || product.originalPrice)}
              </div>
            )}
          </div>

          <a 
            href={product.affiliateUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            className="w-full flex items-center justify-center gap-3 bg-[#EE4D2D] text-white py-4 rounded-2xl font-black text-xs md:text-sm hover:bg-gray-950 transition-all shadow-xl shadow-orange-100 active:scale-95 transform uppercase italic tracking-wider"
          >
            Mua Ngay <ExternalLink size={16} className="group-hover:translate-x-1 transition-transform" />
          </a>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  ChevronRight, 
  Facebook, 
  MessageCircle, 
  ShieldCheck, 
  Phone, 
  RefreshCw,
  Zap,
  ArrowUp
} from 'lucide-react';
import { WHY_US, SHEET_CSV_URL } from './constants';
import { Category, Product, BadgeType } from './types';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('Tất cả');
  const [scrolled, setScrolled] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const CONTACT = {
    phone: "0369333910",
    zalo: "https://zalo.me/0369333910",
    facebook: "https://www.facebook.com/tongkhotusaytiettrung",
    address: "Tổng Kho Tủ Sấy UV, TP. Hồ Chí Minh & Hà Nội"
  };

  const fixImageUrl = (url: string) => {
    if (!url || typeof url !== 'string' || url.trim() === '') {
      return 'https://via.placeholder.com/600x600?text=H%C3%ACnh+%E1%BA%A3nh+đang+cập+nhật';
    }
    const trimmedUrl = url.trim();
    if (trimmedUrl.includes('drive.google.com')) {
      let driveId = '';
      const dMatch = trimmedUrl.match(/\/d\/([a-zA-Z0-9_-]{25,})/);
      if (dMatch && dMatch[1]) driveId = dMatch[1];
      else {
        const idMatch = trimmedUrl.match(/[?&]id=([a-zA-Z0-9_-]{25,})/);
        if (idMatch && idMatch[1]) driveId = idMatch[1];
      }
      if (driveId) return `https://drive.google.com/thumbnail?id=${driveId}&sz=w1000`;
    }
    return trimmedUrl;
  };

  const parsePrice = (val: any): number => {
    if (!val) return 0;
    const cleanValue = val.toString()
      .replace(/[.\s,đĐvVnNlL-]/g, '')
      .trim();
    return parseInt(cleanValue, 10) || 0;
  };

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', handleScroll);
    fetchData();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${SHEET_CSV_URL}&t=${new Date().getTime()}`);
      if (!response.ok) throw new Error('Không thể tải dữ liệu');
      const csvText = await response.text();
      const lines = csvText.split(/\r?\n/);
      const dataRows = lines.slice(1).filter(line => line.trim().length > 10); 

      const parsedProducts: Product[] = dataRows
        .map((line, index) => {
          const columns = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);
          const clean = (val: string) => val?.replace(/^"|"$/g, '').trim() || '';
          if (columns.length < 7) return null;

          const category = clean(columns[0]) || 'Khác';
          const name = clean(columns[1]);
          const affiliateUrl = clean(columns[3] || '#');
          const imageUrl = fixImageUrl(clean(columns[4]));
          let original = parsePrice(clean(columns[5])); 
          let discounted = parsePrice(clean(columns[6]));

          if (discounted === 0 && original > 0) discounted = original;
          if (original === 0 && discounted > 0) original = discounted;
          if (original > 0 && discounted > original) {
            [original, discounted] = [discounted, original];
          }

          const badges: BadgeType[] = [];
          if (discounted < original) badges.push('Giảm sâu');

          return {
            id: `p-${index}`,
            name,
            category,
            originalPrice: original,
            discountedPrice: discounted,
            imageUrl,
            affiliateUrl,
            badges
          };
        })
        .filter((p): p is Product => p !== null && p.name !== '');

      setProducts(parsedProducts);
      setLastUpdated(new Date().toLocaleTimeString('vi-VN'));
    } catch (err) {
      console.error("Lỗi đồng bộ:", err);
    } finally {
      setLoading(false);
    }
  };

  const categories = useMemo(() => {
    const unique = Array.from(new Set(products.map(p => p.category))).filter(Boolean);
    return ['Tất cả', ...unique];
  }, [products]);

  const filteredProducts = useMemo(() => {
    if (activeCategory === 'Tất cả') return products;
    return products.filter(p => p.category === activeCategory);
  }, [activeCategory, products]);

  return (
    <div className="min-h-screen flex flex-col selection:bg-orange-100 selection:text-orange-600 bg-white antialiased">
      {/* Top Bar Status */}
      <div className="bg-gray-950 text-white py-2.5 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] z-[60] relative border-b border-gray-800">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2.5">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </span>
              <span className="hidden sm:inline opacity-80 uppercase tracking-wider">Hệ thống đồng bộ trực tuyến</span>
              <span className="sm:hidden">LIVE</span>
            </div>
          </div>
          <div className="flex items-center gap-8">
            <span className="text-gray-500 hidden md:inline italic opacity-60 uppercase">Data Refreshed: {lastUpdated}</span>
            <a href={`tel:${CONTACT.phone}`} className="text-[#EE4D2D] hover:text-white transition-colors flex items-center gap-1.5 font-black">
              <Phone size={12} className="fill-[#EE4D2D]" /> {CONTACT.phone}
            </a>
          </div>
        </div>
      </div>

      <header className={`fixed top-10 left-0 right-0 z-50 transition-all duration-500 ${scrolled ? 'bg-white/95 shadow-xl py-4 top-0 backdrop-blur-md border-b border-gray-100' : 'bg-transparent py-10'}`}>
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-4 group cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
            <div className={`p-3 rounded-2xl transition-all duration-500 shadow-lg ${scrolled ? 'bg-[#EE4D2D]' : 'bg-white'}`}>
              <ShieldCheck className={scrolled ? 'text-white w-7 h-7' : 'text-[#EE4D2D] w-7 h-7'} />
            </div>
            <div className="flex flex-col">
              <span className="text-xl md:text-3xl font-black tracking-tighter uppercase text-gray-950 leading-none">
                TỔNG KHO <span className="text-[#EE4D2D]">UV</span>
              </span>
              <span className="text-[9px] font-bold text-gray-400 uppercase tracking-[0.5em] mt-1.5 opacity-80 italic">Premium Catalog</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={fetchData} className="p-3.5 rounded-2xl border bg-white hover:bg-gray-50 transition-all border-gray-100 hidden sm:flex shadow-sm">
              <RefreshCw size={20} className={`${loading ? 'animate-spin text-[#EE4D2D]' : 'text-gray-400'}`} />
            </button>
            <a href={CONTACT.zalo} target="_blank" rel="noopener noreferrer" className="bg-[#EE4D2D] text-white px-8 md:px-12 py-4 rounded-2xl font-black text-sm md:text-base shadow-2xl shadow-orange-200 hover:scale-[1.03] active:scale-95 transition-all uppercase italic tracking-wide">
              Kết nối Zalo
            </a>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <section className="relative pt-64 pb-28 md:pt-80 md:pb-60 overflow-hidden bg-white">
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none">
           <div className="absolute top-0 left-1/4 w-[900px] h-[900px] bg-orange-50/60 rounded-full blur-[200px] opacity-40"></div>
           <div className="absolute bottom-0 right-1/4 w-[700px] h-[700px] bg-blue-50/50 rounded-full blur-[180px] opacity-30"></div>
        </div>

        <div className="container mx-auto px-4 text-center relative z-10">
