          <h1 className="text-6xl md:text-[100px] font-black text-gray-950 mb-12 leading-[1.1] tracking-tighter italic uppercase">
            Kho <span className="text-[#EE4D2D]">Tủ Sấy UV</span> <br className="hidden md:block"/>
            <span className="relative inline-block mt-3">Giá Tận Gốc Online</span>
          </h1>

          <p className="text-gray-500 text-lg md:text-2xl max-w-4xl mx-auto mb-20 leading-[1.6] font-medium italic px-4 opacity-80">
            Phân phối sỉ lẻ thiết bị tiệt trùng tia cực tím chuyên dụng <br className="hidden md:block"/> 
            cho gia đình, nhà hàng, Spa & cơ sở y tế.
          </p>

          <button 
            onClick={() => document.getElementById('catalog')?.scrollIntoView({ behavior: 'smooth' })} 
            className="group bg-[#EE4D2D] text-white px-24 py-8 rounded-[2.8rem] font-black text-xl shadow-2xl shadow-orange-300/40 hover:bg-gray-950 transition-all transform hover:-translate-y-2 flex items-center justify-center gap-4 uppercase italic mx-auto active:scale-95"
